import React, { useState } from 'react';
import { Outlet, NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import Toast from './Toast';
import './Layout.css';

const ROLE_COLORS = { admin: '#ef4444', manager: '#f4a11a', customer: '#3b82f6', technician: '#22c55e' };

const NAV_ITEMS = [
  { path: '/', label: 'Dashboard', icon: '📊', exact: true, roles: ['admin','manager','customer','technician'] },
  { path: '/equipment', label: 'Equipment', icon: '🏗️', roles: ['admin','manager','customer','technician'] },
  { path: '/rentals', label: 'Rental Orders', icon: '📦', roles: ['admin','manager','customer'] },
  { path: '/requests', label: 'Requests', icon: '📋', badge: true, roles: ['admin','manager','customer'] },
  { path: '/maintenance', label: 'Maintenance', icon: '🔧', badge: true, roles: ['admin','manager','technician'] },
  { path: '/cicd', label: 'CI/CD Pipelines', icon: '🔄', roles: ['admin','manager'] },
  { path: '/monitoring', label: 'Monitoring', icon: '📡', roles: ['admin','manager','technician'] },
  { path: '/reports', label: 'Reports', icon: '📈', roles: ['admin','manager'] },
  { path: '/users', label: 'User Management', icon: '👥', roles: ['admin'] },
];

export default function Layout() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [sidebarOpen, setSidebarOpen] = useState(false);

  const handleLogout = async () => {
    await logout();
    navigate('/login');
  };

  const avatarColor = ROLE_COLORS[user?.role] || '#f4a11a';
  const visibleNav = NAV_ITEMS.filter(n => n.roles.includes(user?.role));

  return (
    <div className="app-shell">
      {/* ── Topbar ── */}
      <header className="topbar">
        <button className="burger" onClick={() => setSidebarOpen(o => !o)}>☰</button>
        <div className="topbar-logo">RENTFORGE</div>
        <span className="topbar-sep">|</span>
        <div className="topbar-subtitle">Equipment Rental Management System</div>
        <div className="topbar-right">
          <div className="user-chip">
            <div className="user-avatar" style={{ background: avatarColor }}>
              {user?.name?.[0]?.toUpperCase()}
            </div>
            <div className="user-info">
              <div className="user-name">{user?.name}</div>
              <div className="user-role">{user?.role}</div>
            </div>
          </div>
          <button className="btn btn-ghost btn-sm" onClick={handleLogout}>Logout</button>
        </div>
      </header>

      {/* ── Sidebar ── */}
      <aside className={`sidebar ${sidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-inner">
          <div className="sidebar-section">Navigation</div>
          {visibleNav.map(item => (
            <NavLink
              key={item.path}
              to={item.path}
              end={item.exact}
              className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}
              onClick={() => setSidebarOpen(false)}
            >
              <span className="nav-icon">{item.icon}</span>
              <span className="nav-label">{item.label}</span>
            </NavLink>
          ))}
        </div>
      </aside>

      {/* Sidebar overlay (mobile) */}
      {sidebarOpen && <div className="sidebar-overlay" onClick={() => setSidebarOpen(false)} />}

      {/* ── Main ── */}
      <main className="main-content">
        <div className="page-wrapper slide-up">
          <Outlet />
        </div>
      </main>

      <Toast />
    </div>
  );
}
